export type AppRole = "simple_utilisateur" | "responsable" | "administrateur";

export const normalizeRole = (role?: string | null): AppRole | null => {
  if (!role) return null;

  // Accept legacy formats such as ROLE_ADMINISTRATEUR, "simple utilisateur", or "admin".
  const cleaned = role.trim().toLowerCase().replace(/[\s-]+/g, "_");
  const normalized = cleaned.startsWith("role_") ? cleaned.slice(5) : cleaned;

  if (normalized === "simple_utilisateur" || normalized === "simpleutilisateur" || normalized === "simple") {
    return "simple_utilisateur";
  }
  if (normalized === "responsable") {
    return "responsable";
  }
  if (normalized === "administrateur" || normalized === "admin") {
    return "administrateur";
  }

  return null;
};

export const canAccessRole = (allowedRoles: AppRole[], role?: string | null) => {
  const normalizedRole = normalizeRole(role);
  return normalizedRole ? allowedRoles.includes(normalizedRole) : false;
};

export const getDefaultRoute = (role?: string | null) => {
  const normalizedRole = normalizeRole(role);
  if (normalizedRole === "simple_utilisateur") {
    return "/formations";
  }
  if (normalizedRole === "responsable" || normalizedRole === "administrateur") {
    return "/dashboard";
  }
  return "/login";
};

import { useEffect, useState } from "react";
import DataTable from "@/components/shared/DataTable";
import API from "@/services/api";
import { Domaine } from "@/types";
import { useToast } from "@/hooks/use-toast";

const DomainesPage = () => {
  const [domaines, setDomaines] = useState<Domaine[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const { toast } = useToast();

  useEffect(() => {
    loadDomaines();
  }, []);

  const loadDomaines = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/domaines");
      setDomaines(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      toast({ title: "Erreur", description: "Impossible de charger les domaines" });
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (domaine: Domaine) => {
    if (window.confirm("Êtes-vous sûr de vouloir supprimer ce domaine ?")) {
      try {
        await API.delete(`/domaines/${domaine.id}`);
        toast({ title: "Succès", description: "Domaine supprimé" });
        loadDomaines();
      } catch (error) {
        console.error("Erreur:", error);
        toast({ title: "Erreur", description: "Impossible de supprimer le domaine" });
      }
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "libelle", label: "Libellé" },
  ];

  return (
    <DataTable<Domaine>
      title="Domaines"
      description="Gérer les domaines de formation"
      columns={columns}
      data={domaines}
      searchKey="libelle"
      searchPlaceholder="Rechercher un domaine..."
      isLoading={isLoading}
      onAdd={() => toast({ title: "Ajouter un domaine", description: "Fonctionnalité à venir" })}
      onEdit={() => toast({ title: "Modifier", description: "Fonctionnalité à venir" })}
      onDelete={handleDelete}
    />
  );
};

export default DomainesPage;

import { useEffect, useState } from "react";
import DataTable from "@/components/shared/DataTable";
import CrudFormModal from "@/components/shared/CrudFormModal";
import API from "@/services/api";
import { Domaine } from "@/types";
import { useToast } from "@/hooks/use-toast";

const DomainesPage = () => {
  const [domaines, setDomaines] = useState<Domaine[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingDomaine, setEditingDomaine] = useState<Domaine | null>(null);
  const [libelle, setLibelle] = useState("");
  const [formError, setFormError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();

  const notify = (title: string, description: string) =>
    toast({ id: Date.now().toString(), title, description });

  useEffect(() => {
    loadDomaines();
  }, []);

  const loadDomaines = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/domaines");
      setDomaines(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de charger les domaines");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (domaine: Domaine) => {
    try {
      await API.delete(`/domaines/${domaine.id}`);
      notify("Succès", "Domaine supprimé");
      loadDomaines();
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de supprimer le domaine");
    }
  };

  const openAddModal = () => {
    setEditingDomaine(null);
    setLibelle("");
    setFormError("");
    setIsModalOpen(true);
  };

  const openEditModal = (domaine: Domaine) => {
    setEditingDomaine(domaine);
    setLibelle(domaine.libelle);
    setFormError("");
    setIsModalOpen(true);
  };

  const handleSubmit = async () => {
    const value = libelle.trim();
    if (!value) {
      setFormError("Le libellé est obligatoire");
      return;
    }

    setIsSubmitting(true);
    setFormError("");
    try {
      if (editingDomaine) {
        await API.put(`/domaines/${editingDomaine.id}`, { id: editingDomaine.id, libelle: value });
        notify("Succès", "Domaine modifié");
      } else {
        await API.post("/domaines", { libelle: value });
        notify("Succès", "Domaine ajouté");
      }
      setIsModalOpen(false);
      loadDomaines();
    } catch (error) {
      console.error("Erreur:", error);
      setFormError(editingDomaine ? "Impossible de modifier le domaine" : "Impossible d'ajouter le domaine");
    } finally {
      setIsSubmitting(false);
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "libelle", label: "Libellé" },
  ];

  return (
    <>
      <DataTable<Domaine>
        title="Domaines"
        description="Gérer les domaines de formation"
        columns={columns}
        data={domaines}
        searchKey="libelle"
        searchPlaceholder="Rechercher un domaine..."
        isLoading={isLoading}
        onAdd={openAddModal}
        onEdit={openEditModal}
        onDelete={handleDelete}
      />
      <CrudFormModal
        open={isModalOpen}
        title={editingDomaine ? "Modifier un domaine" : "Ajouter un domaine"}
        fields={[{ key: "libelle", label: "Libellé", required: true, placeholder: "Ex: Informatique" }]}
        values={{ libelle }}
        error={formError}
        isSubmitting={isSubmitting}
        submitLabel={editingDomaine ? "Modifier" : "Ajouter"}
        onChange={(_, value) => setLibelle(value)}
        onClose={() => setIsModalOpen(false)}
        onSubmit={handleSubmit}
      />
    </>
  );
};

