import { useEffect, useState } from "react";
import DataTable from "@/components/shared/DataTable";
import API from "@/services/api";
import { Employeur } from "@/types";
import { useToast } from "@/hooks/use-toast";

const EmployeursPage = () => {
  const [employeurs, setEmployeurs] = useState<Employeur[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const { toast } = useToast();

  useEffect(() => {
    loadEmployeurs();
  }, []);

  const loadEmployeurs = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/employeurs");
      setEmployeurs(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      toast({ title: "Erreur", description: "Impossible de charger les employeurs" });
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (employeur: Employeur) => {
    if (window.confirm("Êtes-vous sûr de vouloir supprimer cet employeur ?")) {
      try {
        await API.delete(`/employeurs/${employeur.id}`);
        toast({ title: "Succès", description: "Employeur supprimé" });
        loadEmployeurs();
      } catch (error) {
        console.error("Erreur:", error);
        toast({ title: "Erreur", description: "Impossible de supprimer l'employeur" });
      }
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "nomEmployeur", label: "Nom" },
  ];

  return (
    <DataTable<Employeur>
      title="Employeurs"
      description="Gérer les employeurs externes"
      columns={columns}
      data={employeurs}
      searchKey="nomEmployeur"
      searchPlaceholder="Rechercher un employeur..."
      isLoading={isLoading}
      onAdd={() => toast({ title: "Ajouter un employeur", description: "Fonctionnalité à venir" })}
      onEdit={() => toast({ title: "Modifier", description: "Fonctionnalité à venir" })}
      onDelete={handleDelete}
    />
  );
};

export default EmployeursPage;

import { useEffect, useState } from "react";
import DataTable from "@/components/shared/DataTable";
import CrudFormModal from "@/components/shared/CrudFormModal";
import API from "@/services/api";
import { Employeur } from "@/types";
import { useToast } from "@/hooks/use-toast";

const EmployeursPage = () => {
  const [employeurs, setEmployeurs] = useState<Employeur[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingEmployeur, setEditingEmployeur] = useState<Employeur | null>(null);
  const [nomEmployeur, setNomEmployeur] = useState("");
  const [formError, setFormError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();

  const notify = (title: string, description: string) =>
    toast({ id: Date.now().toString(), title, description });

  useEffect(() => {
    loadEmployeurs();
  }, []);

  const loadEmployeurs = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/employeurs");
      setEmployeurs(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de charger les employeurs");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (employeur: Employeur) => {
    try {
      await API.delete(`/employeurs/${employeur.id}`);
      notify("Succès", "Employeur supprimé");
      loadEmployeurs();
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de supprimer l'employeur");
    }
  };

  const openAddModal = () => {
    setEditingEmployeur(null);
    setNomEmployeur("");
    setFormError("");
    setIsModalOpen(true);
  };

  const openEditModal = (employeur: Employeur) => {
    setEditingEmployeur(employeur);
    setNomEmployeur(employeur.nomEmployeur);
    setFormError("");
    setIsModalOpen(true);
  };

  const handleSubmit = async () => {
    const value = nomEmployeur.trim();
    if (!value) {
      setFormError("Le nom de l'employeur est obligatoire");
      return;
    }

    setIsSubmitting(true);
    setFormError("");
    try {
      if (editingEmployeur) {
        await API.put(`/employeurs/${editingEmployeur.id}`, { id: editingEmployeur.id, nomEmployeur: value });
        notify("Succès", "Employeur modifié");
      } else {
        await API.post("/employeurs", { nomEmployeur: value });
        notify("Succès", "Employeur ajouté");
      }
      setIsModalOpen(false);
      loadEmployeurs();
    } catch (error) {
      console.error("Erreur:", error);
      setFormError(editingEmployeur ? "Impossible de modifier l'employeur" : "Impossible d'ajouter l'employeur");
    } finally {
      setIsSubmitting(false);
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "nomEmployeur", label: "Nom" },
  ];

  return (
    <>
      <DataTable<Employeur>
        title="Employeurs"
        description="Gérer les employeurs externes"
        columns={columns}
        data={employeurs}
        searchKey="nomEmployeur"
        searchPlaceholder="Rechercher un employeur..."
        isLoading={isLoading}
        onAdd={openAddModal}
        onEdit={openEditModal}
        onDelete={handleDelete}
      />
      <CrudFormModal
        open={isModalOpen}
        title={editingEmployeur ? "Modifier un employeur" : "Ajouter un employeur"}
        fields={[{ key: "nomEmployeur", label: "Nom employeur", required: true, placeholder: "Ex: TechConsult" }]}
        values={{ nomEmployeur }}
        error={formError}
        isSubmitting={isSubmitting}
        submitLabel={editingEmployeur ? "Modifier" : "Ajouter"}
        onChange={(_, value) => setNomEmployeur(value)}
        onClose={() => setIsModalOpen(false)}
        onSubmit={handleSubmit}
      />
    </>
  );
};

