import { useEffect, useState } from "react";
import DataTable from "@/components/shared/DataTable";
import CrudFormModal from "@/components/shared/CrudFormModal";
import API from "@/services/api";
import { Participant, Profil, Structure } from "@/types";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";

const ParticipantsPage = () => {
  const [participants, setParticipants] = useState<Participant[]>([]);
  const [structures, setStructures] = useState<Structure[]>([]);
  const [profils, setProfils] = useState<Profil[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingParticipant, setEditingParticipant] = useState<Participant | null>(null);
  const [formValues, setFormValues] = useState<Record<string, string>>({
    nom: "",
    prenom: "",
    email: "",
    tel: "",
    structureId: "",
    profilId: "",
  });
  const [formError, setFormError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();

  const notify = (title: string, description: string) =>
    toast({ id: Date.now().toString(), title, description });

  useEffect(() => {
    loadParticipants();
    loadLookups();
  }, []);

  const loadLookups = async () => {
    try {
      const [structuresRes, profilsRes] = await Promise.all([API.get("/structures"), API.get("/profils")]);
      setStructures(structuresRes.data || []);
      setProfils(profilsRes.data || []);
    } catch (error) {
      console.error("Erreur:", error);
    }
  };

  const loadParticipants = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/participants");
      setParticipants(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de charger les participants");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (participant: Participant) => {
    try {
      await API.delete(`/participants/${participant.id}`);
      notify("Succès", "Participant supprimé");
      loadParticipants();
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de supprimer le participant");
    }
  };

  const openAddModal = () => {
    setEditingParticipant(null);
    setFormValues({ nom: "", prenom: "", email: "", tel: "", structureId: "", profilId: "" });
    setFormError("");
    setIsModalOpen(true);
  };

  const openEditModal = (participant: Participant) => {
    setEditingParticipant(participant);
    setFormValues({
      nom: participant.nom ?? "",
      prenom: participant.prenom ?? "",
      email: participant.email ?? "",
      tel: participant.tel ?? "",
      structureId: participant.structure?.id ? String(participant.structure.id) : "",
      profilId: participant.profil?.id ? String(participant.profil.id) : "",
    });
    setFormError("");
    setIsModalOpen(true);
  };

  const handleSubmit = async () => {
    const nom = formValues.nom.trim();
    const prenom = formValues.prenom.trim();
    const email = formValues.email.trim();
    const tel = formValues.tel.trim();
    const structureId = formValues.structureId ? Number(formValues.structureId) : undefined;
    const profilId = formValues.profilId ? Number(formValues.profilId) : undefined;

    if (!nom || !prenom) {
      setFormError("Nom et prénom sont obligatoires");
      return;
    }

    if (formValues.structureId && (!Number.isInteger(structureId) || structureId <= 0)) {
      setFormError("Structure invalide");
      return;
    }

    if (formValues.profilId && (!Number.isInteger(profilId) || profilId <= 0)) {
      setFormError("Profil invalide");
      return;
    }

    setIsSubmitting(true);
    setFormError("");
    try {
      const payload = {
        id: editingParticipant?.id,
        nom,
        prenom,
        email: email || null,
        tel: tel || null,
        structure: structureId ? { id: structureId } : null,
        profil: profilId ? { id: profilId } : null,
      };

      if (editingParticipant) {
        await API.put(`/participants/${editingParticipant.id}`, payload);
        notify("Succès", "Participant modifié");
      } else {
        await API.post("/participants", payload);
        notify("Succès", "Participant ajouté");
      }
      setIsModalOpen(false);
      loadParticipants();
    } catch (error) {
      console.error("Erreur:", error);
      setFormError(editingParticipant ? "Impossible de modifier le participant" : "Impossible d'ajouter le participant");
    } finally {
      setIsSubmitting(false);
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "nom", label: "Nom" },
    { key: "prenom", label: "Prénom" },
    { key: "email", label: "Email" },
    { key: "tel", label: "Téléphone" },
    {
      key: "structure",
      label: "Structure",
      render: (p: Participant) =>
        p.structure ? <Badge variant="outline">#{p.structure.id} - {p.structure.libelle}</Badge> : "—",
    },
    {
      key: "structureId",
      label: "Structure ID",
      render: (p: Participant) => p.structure?.id ?? "—",
    },
    {
      key: "profil",
      label: "Profil",
      render: (p: Participant) =>
        p.profil ? <Badge variant="secondary">#{p.profil.id} - {p.profil.libelle}</Badge> : "—",
    },
    {
      key: "profilId",
      label: "Profil ID",
      render: (p: Participant) => p.profil?.id ?? "—",
    },
  ];

  return (
    <>
      <DataTable<Participant>
        title="Participants"
        description="Gérer les participants aux formations"
        columns={columns}
        data={participants}
        searchPlaceholder="Rechercher un participant..."
        isLoading={isLoading}
        onAdd={openAddModal}
        onEdit={openEditModal}
        onDelete={handleDelete}
      />
      <CrudFormModal
        open={isModalOpen}
        title={editingParticipant ? "Modifier un participant" : "Ajouter un participant"}
        fields={[
          { key: "nom", label: "Nom", required: true },
          { key: "prenom", label: "Prénom", required: true },
          { key: "email", label: "Email", type: "email" },
          { key: "tel", label: "Téléphone" },
          {
            key: "structureId",
            label: "Structure",
            type: "select",
            options: structures.map((s) => ({ value: String(s.id), label: `#${s.id} - ${s.libelle}` })),
          },
          {
            key: "profilId",
            label: "Profil",
            type: "select",
            options: profils.map((p) => ({ value: String(p.id), label: `#${p.id} - ${p.libelle}` })),
          },
        ]}
        values={formValues}
        error={formError}
        isSubmitting={isSubmitting}
        submitLabel={editingParticipant ? "Modifier" : "Ajouter"}
        onChange={(key, value) => setFormValues((prev) => ({ ...prev, [key]: value }))}
        onClose={() => setIsModalOpen(false)}
        onSubmit={handleSubmit}
      />
    </>
  );
};

export default ParticipantsPage;

import { useEffect, useMemo, useState } from "react";
import API from "@/services/api";
import { Formation, Participant, PlanningConflict, PlanningConflictResponse, PlanningEvent } from "@/types";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/context/AuthContext";
import { canAccessRole } from "@/lib/rbac";

const toMonthValue = (d: Date) => `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;

const formatDateKey = (date: Date) =>
  `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}-${String(date.getDate()).padStart(2, "0")}`;

const addDays = (value: string, days: number) => {
  const date = new Date(`${value}T00:00:00`);
  date.setDate(date.getDate() + days);
  return formatDateKey(date);
};

const compareDateStrings = (a: string, b: string) => {
  if (a === b) return 0;
  return a < b ? -1 : 1;
};

const formatDate = (value: string) =>
  new Date(`${value}T00:00:00`).toLocaleDateString("fr-FR", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  });

const PlanningPage = () => {
  const [formations, setFormations] = useState<Formation[]>([]);
  const [participants, setParticipants] = useState<Participant[]>([]);
  const [events, setEvents] = useState<PlanningEvent[]>([]);
  const [monthValue, setMonthValue] = useState(toMonthValue(new Date()));
  const [isLoading, setIsLoading] = useState(true);
  const [selectedFormationId, setSelectedFormationId] = useState<string>("");
  const [selectedStartDate, setSelectedStartDate] = useState<string>("");
  const [selectedParticipantIds, setSelectedParticipantIds] = useState<number[]>([]);
  const [isAssigning, setIsAssigning] = useState(false);
  const [isSavingPlanning, setIsSavingPlanning] = useState(false);
  const [conflicts, setConflicts] = useState<PlanningConflict[]>([]);
  const { toast } = useToast();
  const { userRole } = useAuth();

  const canManagePlanning = canAccessRole(["responsable", "administrateur"], userRole);

  const notify = (title: string, description: string) =>
    toast({ id: Date.now().toString(), title, description });

  const selectedFormation = useMemo(
    () => formations.find((f) => String(f.id) === selectedFormationId) ?? null,
    [formations, selectedFormationId]
  );

  const selectedEndDate = useMemo(() => {
    if (!selectedStartDate || !selectedFormation?.duree) return "";
    return addDays(selectedStartDate, Math.max(0, selectedFormation.duree - 1));
  }, [selectedStartDate, selectedFormation]);

  const selectedRangeDates = useMemo(() => {
    if (!selectedStartDate || !selectedEndDate) return new Set<string>();
    const dates = new Set<string>();
    for (let d = new Date(`${selectedStartDate}T00:00:00`); compareDateStrings(formatDateKey(d), selectedEndDate) <= 0; d.setDate(d.getDate() + 1)) {
      dates.add(formatDateKey(d));
    }
    return dates;
  }, [selectedStartDate, selectedEndDate]);

  useEffect(() => {
    loadBaseData();
  }, []);

  useEffect(() => {
    loadPlanning();
  }, [monthValue]);

  useEffect(() => {
    if (!selectedFormationId) {
      setSelectedParticipantIds([]);
      setSelectedStartDate("");
      return;
    }
    loadAssignedParticipants(Number(selectedFormationId));
  }, [selectedFormationId]);

  useEffect(() => {
    if (!selectedFormation) {
      setSelectedStartDate("");
      return;
    }
    setSelectedStartDate(selectedFormation.dateFormation ?? "");
  }, [selectedFormation]);

  const loadBaseData = async () => {
    setIsLoading(true);
    try {
      const [formationsRes, participantsRes] = await Promise.all([API.get("/formations"), API.get("/participants")]);
      setFormations(formationsRes.data || []);
      setParticipants(participantsRes.data || []);
    } catch {
      notify("Erreur", "Impossible de charger les données de planification");
    } finally {
      setIsLoading(false);
    }
  };

  const loadPlanning = async () => {
    const [year, month] = monthValue.split("-").map(Number);
    const firstDay = `${year}-${String(month).padStart(2, "0")}-01`;
    const lastDay = new Date(year, month, 0).getDate();
    const endDay = `${year}-${String(month).padStart(2, "0")}-${String(lastDay).padStart(2, "0")}`;

    try {
      const planningRes = await API.get("/formations/planning", {
        params: { from: firstDay, to: endDay },
      });
      setEvents(planningRes.data || []);
    } catch {
      notify("Erreur", "Impossible de charger le planning");
    }
  };

  const loadAssignedParticipants = async (formationId: number) => {
    try {
      const res = await API.get(`/formations/${formationId}/participants`);
      const ids = ((res.data || []) as Participant[]).map((p) => p.id);
      setSelectedParticipantIds(ids);
      setConflicts([]);
    } catch {
      notify("Erreur", "Impossible de charger les participants affectés");
    }
  };

  const handleParticipantToggle = (participantId: number) => {
    setSelectedParticipantIds((prev) =>
      prev.includes(participantId) ? prev.filter((id) => id !== participantId) : [...prev, participantId]
    );
  };

  const handleSelectDate = (date: string | null) => {
    if (!canManagePlanning || !selectedFormationId || !date) return;
    setSelectedStartDate(date);
    setConflicts([]);
  };

  const handleSavePlanning = async () => {
    if (!selectedFormation) {
      notify("Information", "Sélectionnez d'abord une formation");
      return;
    }
    if (!selectedStartDate) {
      notify("Information", "Cliquez d'abord sur une date de départ dans le calendrier");
      return;
    }

    setIsSavingPlanning(true);
    setConflicts([]);
    try {
      const payload = {
        id: selectedFormation.id,
        titre: selectedFormation.titre,
        nom: selectedFormation.nom,
        description: selectedFormation.description,
        annee: selectedFormation.annee,
        duree: selectedFormation.duree,
        budget: selectedFormation.budget,
        dateFormation: selectedStartDate,
        lieu: selectedFormation.lieu ?? null,
        domaine: selectedFormation.domaine ? { id: selectedFormation.domaine.id } : null,
        formateur: selectedFormation.formateur ? { id: selectedFormation.formateur.id } : null,
      };

      await API.put(`/formations/${selectedFormation.id}`, payload);
      notify("Succès", "Planning enregistré");
      await loadBaseData();
      await loadPlanning();
    } catch (error: unknown) {
      const apiError = error as { response?: { status?: number; data?: PlanningConflictResponse } };
      if (apiError.response?.status === 409 && apiError.response.data?.conflicts) {
        setConflicts(apiError.response.data.conflicts);
        notify("Conflit détecté", "Le planning ne peut pas être enregistré");
      } else {
        notify("Erreur", "Impossible d'enregistrer le planning");
      }
    } finally {
      setIsSavingPlanning(false);
    }
  };

  const handleAssignParticipants = async () => {
    if (!selectedFormationId) {
      notify("Information", "Sélectionnez d'abord une formation");
      return;
    }

    setIsAssigning(true);
    setConflicts([]);
    try {
      await API.put(`/formations/${selectedFormationId}/participants`, {
        participantIds: selectedParticipantIds,
      });
      notify("Succès", "Affectation des participants mise à jour");
      loadPlanning();
    } catch (error: unknown) {
      const apiError = error as { response?: { status?: number; data?: PlanningConflictResponse } };
      if (apiError.response?.status === 409 && apiError.response.data?.conflicts) {
        setConflicts(apiError.response.data.conflicts);
        notify("Conflit détecté", "Affectation refusée à cause d'un conflit de planning");
      } else {
        notify("Erreur", "Impossible de mettre à jour l'affectation");
      }
    } finally {
      setIsAssigning(false);
    }
  };

  const monthDays = useMemo(() => {
    const [year, month] = monthValue.split("-").map(Number);
    const daysInMonth = new Date(year, month, 0).getDate();
    const firstWeekDay = new Date(year, month - 1, 1).getDay();
    const normalizedFirst = firstWeekDay === 0 ? 7 : firstWeekDay;

    const cells: Array<{ date: string | null; label: string }> = [];
    for (let i = 1; i < normalizedFirst; i += 1) {
      cells.push({ date: null, label: "" });
    }

    for (let day = 1; day <= daysInMonth; day += 1) {
      const date = `${year}-${String(month).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
      cells.push({ date, label: String(day) });
    }

    return cells;
  }, [monthValue]);

  const eventByDay = useMemo(() => {
    const map = new Map<string, PlanningEvent[]>();
    events.forEach((event) => {
      const start = new Date(`${event.startDate}T00:00:00`);
      const end = new Date(`${event.endDate}T00:00:00`);
      for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
        const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
        const arr = map.get(key) ?? [];
        arr.push(event);
        map.set(key, arr);
      }
    });
    return map;
  }, [events]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-3">
        <div>
          <h1 className="page-header">Planning des formations</h1>
          <p className="text-sm text-muted-foreground">Calendrier mensuel + gestion des affectations participants</p>
        </div>
        <input
          type="month"
          className="h-10 rounded-md border border-input bg-background px-3 text-sm"
          value={monthValue}
          onChange={(e) => setMonthValue(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 stat-card space-y-3">
          <div className="grid grid-cols-7 gap-2 text-xs font-semibold text-muted-foreground">
            {["Lun", "Mar", "Mer", "Jeu", "Ven", "Sam", "Dim"].map((d) => (
              <div key={d} className="text-center py-1">{d}</div>
            ))}
          </div>

          <div className="grid grid-cols-7 gap-2">
            {monthDays.map((day, idx) => (
              <button
                key={`${day.date ?? "empty"}-${idx}`}
                type="button"
                onClick={() => handleSelectDate(day.date)}
                className={`min-h-28 border rounded-lg p-2 text-left transition-colors bg-background ${
                  day.date && selectedRangeDates.has(day.date)
                    ? "border-primary bg-primary/10"
                    : "border-border hover:border-primary/40 hover:bg-muted/30"
                } ${day.date && selectedStartDate === day.date ? "ring-2 ring-primary ring-offset-1" : ""}`}
                disabled={!day.date || !canManagePlanning}
              >
                <div className="text-xs font-semibold mb-1">{day.label}</div>
                <div className="space-y-1">
                  {(day.date ? eventByDay.get(day.date) ?? [] : []).slice(0, 3).map((event) => (
                    <div key={`${event.id}-${day.date}`} className="rounded bg-primary/10 px-2 py-1 text-[11px] text-primary">
                      {event.titre}
                    </div>
                  ))}
                  {(day.date ? eventByDay.get(day.date)?.length ?? 0 : 0) > 3 && (
                    <div className="text-[11px] text-muted-foreground">+
                      {(eventByDay.get(day.date as string)?.length ?? 0) - 3} autres
                    </div>
                  )}
                </div>
              </button>
            ))}
          </div>
        </div>

        <div className="stat-card space-y-4">
          <h3 className="font-semibold">Affectation participants</h3>
          {!canManagePlanning ? (
            <p className="text-sm text-muted-foreground">Lecture seule pour votre rôle.</p>
          ) : (
            <>
              <div className="space-y-2">
                <label className="text-sm font-medium">Formation</label>
                <select
                  className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                  value={selectedFormationId}
                  onChange={(e) => setSelectedFormationId(e.target.value)}
                >
                  <option value="">Sélectionner...</option>
                  {formations.map((formation) => (
                    <option key={formation.id} value={formation.id}>
                      #{formation.id} - {formation.titre}
                    </option>
                  ))}
                </select>
              </div>

              {selectedFormation ? (
                <div className="rounded-md border border-border p-3 bg-muted/20 text-sm space-y-1">
                  <p><span className="font-medium">Date:</span> {selectedFormation.dateFormation ? formatDate(selectedFormation.dateFormation) : "—"}</p>
                  <p><span className="font-medium">Durée:</span> {selectedFormation.duree} jour(s)</p>
                  <p><span className="font-medium">Lieu:</span> {selectedFormation.lieu || "—"}</p>
                </div>
              ) : null}

              {selectedFormation && canManagePlanning ? (
                <div className="rounded-md border border-primary/20 bg-primary/5 p-3 text-sm space-y-2">
                  <p className="font-medium text-primary">Planification active</p>
                  <p>Jour cliqué: {selectedStartDate ? formatDate(selectedStartDate) : "Aucun"}</p>
                  <p>
                    Fin prévue: {selectedEndDate ? formatDate(selectedEndDate) : "—"}
                  </p>
                  <p>
                    Période: {selectedStartDate ? formatDate(selectedStartDate) : "—"} → {selectedEndDate ? formatDate(selectedEndDate) : "—"}
                  </p>
                  <Button onClick={handleSavePlanning} disabled={isSavingPlanning || !selectedStartDate} className="w-full">
                    {isSavingPlanning ? "Enregistrement..." : "Enregistrer le planning"}
                  </Button>
                </div>
              ) : null}

              <div className="space-y-2">
                <label className="text-sm font-medium">Participants</label>
                <div className="max-h-64 overflow-y-auto rounded-md border border-border p-2 space-y-1">
                  {participants.map((participant) => {
                    const checked = selectedParticipantIds.includes(participant.id);
                    return (
                      <label key={participant.id} className="flex items-center gap-2 text-sm py-1 px-1 rounded hover:bg-muted/40">
                        <input
                          type="checkbox"
                          checked={checked}
                          onChange={() => handleParticipantToggle(participant.id)}
                        />
                        <span>#{participant.id} - {participant.prenom} {participant.nom}</span>
                      </label>
                    );
                  })}
                </div>
              </div>

              <Button onClick={handleAssignParticipants} disabled={isAssigning || !selectedFormationId}>
                {isAssigning ? "Enregistrement..." : "Enregistrer l'affectation"}
              </Button>
            </>
          )}
        </div>
      </div>

      {conflicts.length > 0 && (
        <div className="stat-card border border-destructive/40 bg-destructive/5">
          <h3 className="font-semibold text-destructive mb-3">Conflits détectés</h3>
          <div className="space-y-2">
            {conflicts.map((conflict, index) => (
              <div key={`${conflict.type}-${conflict.formationId}-${conflict.participantId}-${index}`} className="rounded-md border border-destructive/30 bg-background p-3">
                <div className="flex items-center gap-2 mb-1">
                  <Badge variant="outline" className="border-destructive/40 text-destructive">
                    {conflict.type}
                  </Badge>
                  {conflict.formationId ? <span className="text-sm">Formation #{conflict.formationId}</span> : null}
                </div>
                <p className="text-sm">{conflict.details}</p>
                {conflict.participantNom ? (
                  <p className="text-xs text-muted-foreground mt-1">Participant concerné: {conflict.participantNom}</p>
                ) : null}
              </div>
            ))}
          </div>
        </div>
      )}

      <div className="stat-card">
        <h3 className="font-semibold mb-2">Liste des sessions du mois</h3>
        {isLoading ? (
          <p className="text-sm text-muted-foreground">Chargement...</p>
        ) : events.length === 0 ? (
          <p className="text-sm text-muted-foreground">Aucune session planifiée sur ce mois.</p>
        ) : (
          <div className="space-y-2">
            {events.map((event) => (
              <div key={event.id} className="rounded-md border border-border p-3 bg-muted/20">
                <p className="font-medium">#{event.id} - {event.titre}</p>
                <p className="text-sm text-muted-foreground">
                  {formatDate(event.startDate)} - {formatDate(event.endDate)} | {event.lieu || "Sans lieu"}
                </p>
                <p className="text-sm text-muted-foreground">
                  Formateur: {event.formateurNom || "Non affecté"} | Participants: {event.participantsCount}
                </p>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default PlanningPage;

import { useEffect, useState } from "react";
import DataTable from "@/components/shared/DataTable";
import API from "@/services/api";
import { Structure } from "@/types";
import { useToast } from "@/hooks/use-toast";

const StructuresPage = () => {
  const [structures, setStructures] = useState<Structure[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const { toast } = useToast();

  useEffect(() => {
    loadStructures();
  }, []);

  const loadStructures = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/structures");
      setStructures(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      toast({ title: "Erreur", description: "Impossible de charger les structures" });
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (structure: Structure) => {
    if (window.confirm("Êtes-vous sûr de vouloir supprimer cette structure ?")) {
      try {
        await API.delete(`/structures/${structure.id}`);
        toast({ title: "Succès", description: "Structure supprimée" });
        loadStructures();
      } catch (error) {
        console.error("Erreur:", error);
        toast({ title: "Erreur", description: "Impossible de supprimer la structure" });
      }
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "libelle", label: "Libellé" },
  ];

  return (
    <DataTable<Structure>
      title="Structures"
      description="Gérer les structures organisationnelles"
      columns={columns}
      data={structures}
      searchKey="libelle"
      searchPlaceholder="Rechercher une structure..."
      isLoading={isLoading}
      onAdd={() => toast({ title: "Ajouter une structure", description: "Fonctionnalité à venir" })}
      onEdit={() => toast({ title: "Modifier", description: "Fonctionnalité à venir" })}
      onDelete={handleDelete}
    />
  );
};

export default StructuresPage;

import { useEffect, useState } from "react";
import DataTable from "@/components/shared/DataTable";
import CrudFormModal from "@/components/shared/CrudFormModal";
import API from "@/services/api";
import { Structure } from "@/types";
import { useToast } from "@/hooks/use-toast";

const StructuresPage = () => {
  const [structures, setStructures] = useState<Structure[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingStructure, setEditingStructure] = useState<Structure | null>(null);
  const [libelle, setLibelle] = useState("");
  const [formError, setFormError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();

  const notify = (title: string, description: string) =>
    toast({ id: Date.now().toString(), title, description });

  useEffect(() => {
    loadStructures();
  }, []);

  const loadStructures = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/structures");
      setStructures(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de charger les structures");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (structure: Structure) => {
    try {
      await API.delete(`/structures/${structure.id}`);
      notify("Succès", "Structure supprimée");
      loadStructures();
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de supprimer la structure");
    }
  };

  const openAddModal = () => {
    setEditingStructure(null);
    setLibelle("");
    setFormError("");
    setIsModalOpen(true);
  };

  const openEditModal = (structure: Structure) => {
    setEditingStructure(structure);
    setLibelle(structure.libelle);
    setFormError("");
    setIsModalOpen(true);
  };

  const handleSubmit = async () => {
    const value = libelle.trim();
    if (!value) {
      setFormError("Le libellé est obligatoire");
      return;
    }

    setIsSubmitting(true);
    setFormError("");
    try {
      if (editingStructure) {
        await API.put(`/structures/${editingStructure.id}`, { id: editingStructure.id, libelle: value });
        notify("Succès", "Structure modifiée");
      } else {
        await API.post("/structures", { libelle: value });
        notify("Succès", "Structure ajoutée");
      }
      setIsModalOpen(false);
      loadStructures();
    } catch (error) {
      console.error("Erreur:", error);
      setFormError(editingStructure ? "Impossible de modifier la structure" : "Impossible d'ajouter la structure");
    } finally {
      setIsSubmitting(false);
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "libelle", label: "Libellé" },
  ];

  return (
    <>
      <DataTable<Structure>
        title="Structures"
        description="Gérer les structures organisationnelles"
        columns={columns}
        data={structures}
        searchKey="libelle"
        searchPlaceholder="Rechercher une structure..."
        isLoading={isLoading}
        onAdd={openAddModal}
        onEdit={openEditModal}
        onDelete={handleDelete}
      />
      <CrudFormModal
        open={isModalOpen}
        title={editingStructure ? "Modifier une structure" : "Ajouter une structure"}
        fields={[{ key: "libelle", label: "Libellé", required: true, placeholder: "Ex: Direction Centrale" }]}
        values={{ libelle }}
        error={formError}
        isSubmitting={isSubmitting}
        submitLabel={editingStructure ? "Modifier" : "Ajouter"}
        onChange={(_, value) => setLibelle(value)}
        onClose={() => setIsModalOpen(false)}
        onSubmit={handleSubmit}
      />
    </>
  );
};

export default StructuresPage;

import { useEffect, useState } from "react";
import DataTable from "@/components/shared/DataTable";
import CrudFormModal from "@/components/shared/CrudFormModal";
import API from "@/services/api";
import { Utilisateur } from "@/types";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";

const ROLE_OPTIONS = [
  { id: 1, nom: "simple_utilisateur" },
  { id: 2, nom: "responsable" },
  { id: 3, nom: "administrateur" },
];

const UtilisateursPage = () => {
  const [utilisateurs, setUtilisateurs] = useState<Utilisateur[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingUtilisateur, setEditingUtilisateur] = useState<Utilisateur | null>(null);
  const [formValues, setFormValues] = useState<Record<string, string>>({
    login: "",
    password: "",
    roleId: "3",
  });
  const [formError, setFormError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();

  const notify = (title: string, description: string) =>
    toast({ id: Date.now().toString(), title, description });

  useEffect(() => {
    loadUtilisateurs();
  }, []);

  const loadUtilisateurs = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/utilisateurs");
      setUtilisateurs(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de charger les utilisateurs");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (utilisateur: Utilisateur) => {
    try {
      await API.delete(`/utilisateurs/${utilisateur.id}`);
      notify("Succès", "Utilisateur supprimé");
      loadUtilisateurs();
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de supprimer l'utilisateur");
    }
  };

  const openAddModal = () => {
    setEditingUtilisateur(null);
    setFormValues({ login: "", password: "", roleId: "3" });
    setFormError("");
    setIsModalOpen(true);
  };

  const openEditModal = (utilisateur: Utilisateur) => {
    setEditingUtilisateur(utilisateur);
    setFormValues({
      login: utilisateur.login ?? "",
      password: "",
      roleId: utilisateur.role?.id ? String(utilisateur.role.id) : "3",
    });
    setFormError("");
    setIsModalOpen(true);
  };

  const handleSubmit = async () => {
    const login = formValues.login.trim();
    const password = formValues.password.trim();
    const roleId = Number(formValues.roleId);

    if (!login || !password) {
      setFormError("Login et mot de passe sont obligatoires");
      return;
    }
    if (!Number.isInteger(roleId) || !ROLE_OPTIONS.some((r) => r.id === roleId)) {
      setFormError("Rôle invalide");
      return;
    }

    setIsSubmitting(true);
    setFormError("");
    try {
      const payload = {
        id: editingUtilisateur?.id,
        login,
        password,
        role: { id: roleId },
      };

      if (editingUtilisateur) {
        await API.put(`/utilisateurs/${editingUtilisateur.id}`, payload);
        notify("Succès", "Utilisateur modifié");
      } else {
        await API.post("/utilisateurs", payload);
        notify("Succès", "Utilisateur ajouté");
      }
      setIsModalOpen(false);
      loadUtilisateurs();
    } catch (error) {
      console.error("Erreur:", error);
      setFormError(editingUtilisateur ? "Impossible de modifier l'utilisateur" : "Impossible d'ajouter l'utilisateur");
    } finally {
      setIsSubmitting(false);
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "login", label: "Login" },
    {
      key: "password",
      label: "Mot de passe",
      render: () => <Badge variant="outline">••••••••</Badge>,
    },
    {
      key: "role",
      label: "Rôle",
      render: (u: Utilisateur) => (u.role ? `#${u.role.id} - ${u.role.nom}` : "—"),
    },
    {
      key: "roleId",
      label: "Rôle ID",
      render: (u: Utilisateur) => u.role?.id ?? "—",
    },
  ];

  return (
    <>
      <DataTable<Utilisateur>
        title="Utilisateurs"
        description="Gérer les utilisateurs du système"
        columns={columns}
        data={utilisateurs}
        searchKey="login"
        searchPlaceholder="Rechercher un utilisateur..."
        isLoading={isLoading}
        onAdd={openAddModal}
        onEdit={openEditModal}
        onDelete={handleDelete}
      />
      <CrudFormModal
        open={isModalOpen}
        title={editingUtilisateur ? "Modifier un utilisateur" : "Ajouter un utilisateur"}
        fields={[
          { key: "login", label: "Login", required: true },
          { key: "password", label: editingUtilisateur ? "Nouveau mot de passe" : "Mot de passe", type: "password", required: true },
          {
            key: "roleId",
            label: "Rôle",
            type: "select",
            required: true,
            options: ROLE_OPTIONS.map((r) => ({ value: String(r.id), label: `${r.nom}` })),
          },
        ]}
        values={formValues}
        error={formError}
        isSubmitting={isSubmitting}
        submitLabel={editingUtilisateur ? "Modifier" : "Ajouter"}
        onChange={(key, value) => setFormValues((prev) => ({ ...prev, [key]: value }))}
        onClose={() => setIsModalOpen(false)}
        onSubmit={handleSubmit}
      />
    </>
  );
};

