package com.gestion.formation.config;

import com.gestion.formation.security.JwtFilter;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.*;
import org.springframework.security.authentication.*;
import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.http.HttpMethod;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.CorsConfigurationSource;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;
import java.util.Arrays;

@Configuration
@EnableWebSecurity
@EnableMethodSecurity
public class SecurityConfig {

    @Autowired
    private JwtFilter jwtFilter;

    @Bean
        CorsConfiguration configuration = new CorsConfiguration();
        configuration.setAllowedOrigins(Arrays.asList("http://localhost:3000", "http://localhost:8081", "http://localhost:5173"));
        configuration.setAllowedMethods(Arrays.asList("*"));
        configuration.setAllowedHeaders(Arrays.asList("*"));
        configuration.setAllowCredentials(true);
        configuration.setExposedHeaders(Arrays.asList("Authorization", "Content-Type"));

        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
        source.registerCorsConfiguration("/**", configuration);
        return source;
    }

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .csrf(csrf -> csrf.disable())
            .cors(cors -> cors.configurationSource(corsConfigurationSource()))
            .sessionManagement(s -> s.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
            .authorizeHttpRequests(auth -> auth
                // PUBLIC ENDPOINTS - LOGIN
                .requestMatchers("/api/auth/**").permitAll()
                .requestMatchers("/api/statistiques/**").hasAnyRole("RESPONSABLE", "ADMINISTRATEUR")
                // Allow all authenticated users to READ domaines, profils, structures (GET)
                // PUBLIC ENDPOINTS - ALL API DATA (permitAll means no authentication required)
                .requestMatchers("/api/**").permitAll()
                // EVERYTHING ELSE - REQUIRES AUTHENTICATION

        return http.build();
    }

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }

    @Bean
    public AuthenticationManager authenticationManager(AuthenticationConfiguration config) throws Exception {
        return config.getAuthenticationManager();
    }
}

package com.gestion.formation.config;

import com.gestion.formation.security.JwtFilter;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.*;
import org.springframework.security.authentication.*;
import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.http.HttpMethod;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.CorsConfigurationSource;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;
import java.util.Arrays;

@Configuration
@EnableWebSecurity
@EnableMethodSecurity
public class SecurityConfig {

    @Autowired
    private JwtFilter jwtFilter;

    @Bean
    public CorsConfigurationSource corsConfigurationSource() {
        CorsConfiguration configuration = new CorsConfiguration();
        configuration.setAllowedOrigins(Arrays.asList("http://localhost:3000", "http://localhost:8081", "http://localhost:5173"));
        configuration.setAllowedMethods(Arrays.asList("*"));
        configuration.setAllowedHeaders(Arrays.asList("*"));
        configuration.setAllowCredentials(true);
        configuration.setExposedHeaders(Arrays.asList("Authorization", "Content-Type"));
        
        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
        source.registerCorsConfiguration("/**", configuration);
        return source;
    }

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .csrf(csrf -> csrf.disable())
            .cors(cors -> cors.configurationSource(corsConfigurationSource()))
            .sessionManagement(s -> s.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/api/auth/**").permitAll()
                .requestMatchers("/api/statistiques/**").hasAnyRole("RESPONSABLE", "ADMINISTRATEUR")
                // Allow all authenticated users to READ domaines, profils, structures (GET)
                .requestMatchers(HttpMethod.GET, "/api/domaines/**").hasAnyRole("SIMPLE_UTILISATEUR", "RESPONSABLE", "ADMINISTRATEUR")
                .requestMatchers(HttpMethod.GET, "/api/profils/**").hasAnyRole("SIMPLE_UTILISATEUR", "RESPONSABLE", "ADMINISTRATEUR")
                .requestMatchers(HttpMethod.GET, "/api/structures/**").hasAnyRole("SIMPLE_UTILISATEUR", "RESPONSABLE", "ADMINISTRATEUR")
                // Restrict modifications (POST, PUT, DELETE) to ADMINISTRATEUR
                .requestMatchers(HttpMethod.POST, "/api/domaines/**").hasRole("ADMINISTRATEUR")
                .requestMatchers(HttpMethod.PUT, "/api/domaines/**").hasRole("ADMINISTRATEUR")
                .requestMatchers(HttpMethod.DELETE, "/api/domaines/**").hasRole("ADMINISTRATEUR")
                .requestMatchers(HttpMethod.POST, "/api/profils/**").hasRole("ADMINISTRATEUR")
                .requestMatchers(HttpMethod.PUT, "/api/profils/**").hasRole("ADMINISTRATEUR")
                .requestMatchers(HttpMethod.DELETE, "/api/profils/**").hasRole("ADMINISTRATEUR")
                .requestMatchers(HttpMethod.POST, "/api/structures/**").hasRole("ADMINISTRATEUR")
                .requestMatchers(HttpMethod.PUT, "/api/structures/**").hasRole("ADMINISTRATEUR")
                .requestMatchers(HttpMethod.DELETE, "/api/structures/**").hasRole("ADMINISTRATEUR")
                // Allow all authenticated users to READ utilisateurs (GET)
                .requestMatchers(HttpMethod.GET, "/api/utilisateurs/**").hasAnyRole("SIMPLE_UTILISATEUR", "RESPONSABLE", "ADMINISTRATEUR")
                // Restrict modifications to ADMINISTRATEUR
                .requestMatchers(HttpMethod.POST, "/api/utilisateurs/**").hasRole("ADMINISTRATEUR")
                .requestMatchers(HttpMethod.PUT, "/api/utilisateurs/**").hasRole("ADMINISTRATEUR")
                .requestMatchers(HttpMethod.DELETE, "/api/utilisateurs/**").hasRole("ADMINISTRATEUR")
                // Allow all authenticated users to READ employeurs (GET)
                .requestMatchers(HttpMethod.GET, "/api/employeurs/**").hasAnyRole("SIMPLE_UTILISATEUR", "RESPONSABLE", "ADMINISTRATEUR")
                // Restrict modifications to RESPONSABLE and ADMINISTRATEUR
                .requestMatchers(HttpMethod.POST, "/api/employeurs/**").hasAnyRole("RESPONSABLE", "ADMINISTRATEUR")
                .requestMatchers(HttpMethod.PUT, "/api/employeurs/**").hasAnyRole("RESPONSABLE", "ADMINISTRATEUR")
                .requestMatchers(HttpMethod.DELETE, "/api/employeurs/**").hasAnyRole("RESPONSABLE", "ADMINISTRATEUR")
                .requestMatchers("/api/formations/**", "/api/formateurs/**", "/api/participants/**").hasAnyRole("SIMPLE_UTILISATEUR", "RESPONSABLE", "ADMINISTRATEUR")
                .requestMatchers(HttpMethod.OPTIONS, "/**").permitAll()
                .anyRequest().authenticated()
            )
            .addFilterBefore(jwtFilter, UsernamePasswordAuthenticationFilter.class);

        return http.build();
    }

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }

    @Bean
    public AuthenticationManager authenticationManager(AuthenticationConfiguration config) throws Exception {
        return config.getAuthenticationManager();
    }
}

package com.gestion.formation.controller;

import com.gestion.formation.entity.Domaine;
