package com.gestion.formation.repository;

import com.gestion.formation.entity.Formation;
import org.springframework.data.jpa.repository.EntityGraph;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import java.util.List;
import java.util.Optional;

public interface FormationRepository extends JpaRepository<Formation, Long> {
    @EntityGraph(attributePaths = {"domaine", "formateur"})
    List<Formation> findAll();

    @EntityGraph(attributePaths = {"domaine", "formateur"})
    Optional<Formation> findById(Long id);

    List<Formation> findByAnnee(Integer annee);
    List<Formation> findByDomaine_Id(Integer domaineId);
    List<Formation> findByFormateur_Id(Integer formateurId);
    List<Formation> findByFormateur_IdAndIdNot(Integer formateurId, Long id);
    List<Formation> findByLieuIgnoreCase(String lieu);
    List<Formation> findByLieuIgnoreCaseAndIdNot(String lieu, Long id);

    @Query("""
            select distinct f from Formation f
            join f.participants p
            where p.id in :participantIds
            and (:excludedFormationId is null or f.id <> :excludedFormationId)
            """)
    List<Formation> findByParticipantIdsForConflict(
            @Param("participantIds") List<Integer> participantIds,
            @Param("excludedFormationId") Long excludedFormationId
    );
}

